import React from 'react';
import { Globe } from 'lucide-react';
import HeroBackground from './hero/HeroBackground';
import HeroContent from './hero/HeroContent';
import ServiceBar from './hero/ServiceBar';
import StatsBar from './hero/StatsBar';

function HeroSection({ lang, setLang, t, scrollToSection }) {
  return (
    <section className="relative min-h-screen overflow-hidden">
      {/* Background gradient */}
      <HeroBackground />

      {/* Main content */}
      <div className="relative z-10 w-full pt-52 pb-20">
        <div className="flex flex-col lg:flex-row items-center justify-between">
          {/* Text content - bên trái */}
          <div style={{ paddingLeft: '10%' }} className="flex-1">
            <HeroContent t={t} scrollToSection={scrollToSection} />
          </div>

          {/* Device mockups - bên phải */}
          <div className="hidden lg:flex flex-1 items-center justify-center relative h-[500px]">
            {/* Tablet - trái */}
            <img 
              src="/images/tablet.jpg" 
              alt="Tablet"
              className="absolute left-0 bottom-10 w-[180px] h-auto transform -rotate-6 shadow-2xl rounded-xl z-10"
            />

            {/* Desktop - giữa */}
            <img 
              src="/images/desktop.jpg" 
              alt="Desktop"
              className="w-[320px] h-auto shadow-2xl rounded-lg z-20"
            />

            {/* Smartphone - phải */}
            <img 
              src="/images/smartphone.jpg" 
              alt="Smartphone"
              className="absolute right-10 bottom-16 w-[100px] h-auto transform rotate-6 shadow-2xl rounded-xl z-30"
            />
          </div>
        </div>

        {/* Language switcher */}
        <div className="absolute top-8 right-8">
          <button 
            onClick={() => setLang(lang === 'vi' ? 'en' : 'vi')} 
            className="flex items-center space-x-2 bg-white/10 backdrop-blur-sm text-white px-4 py-2 rounded-lg hover:bg-white/20 transition-all"
          >
            <Globe className="w-5 h-5" />
            <span className="font-medium">{lang === 'vi' ? 'EN' : 'VI'}</span>
          </button>
        </div>
      </div>

      {/* Service bar */}
      <div className="relative z-20 max-w-5xl mx-auto px-4 -mt-10">
        <ServiceBar lang={lang} />
      </div>

      {/* Stats */}
      <div className="relative z-10 max-w-4xl mx-auto px-4 mt-16 pb-16">
        <StatsBar lang={lang} />
      </div>

      {/* CSS Animations */}
      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-20px); }
        }
        .animate-float { animation: float 6s ease-in-out infinite; }
      `}</style>
    </section>
  );
}

export default HeroSection;
